+function resolveSummaryStyle(rawValue: string | undefined | null): SummaryStyle {
+  if (!rawValue) {
+    return 'compact';
+  }
+  const normalized = rawValue.trim().toLowerCase();
+  if (normalized === 'minimal') {
+    return 'minimal';
+  }
+  if (normalized === 'verbose') {
+    return 'verbose';
+  }
+  if (normalized === 'short' || normalized === 'compact') {
+    return 'compact';
+  }
